# Utils module - helper functions for shape calculations

from shapes import IMeasurable, Rectangle

def total_area(shapes: list[IMeasurable]) -> float:
    total: float = 0.0
    for s in shapes:
        total += s.measure()
    return total

def is_large_rect(r: Rectangle) -> bool:
    return r.measure() > 25.0

def scale_dimensions(width: float, height: float, factor: float) -> tuple[float, float]:
    return (width * factor, height * factor)
